import{_ as a,o as i,c as e,ae as t}from"./chunks/framework.BEtfQoF7.js";const k=JSON.parse('{"title":"엔터프라이즈 네트워크 구성","description":"","frontmatter":{},"headers":[],"relativePath":"network-config.md","filePath":"network-config.md","lastUpdated":1776205703000}'),l={name:"network-config.md"};function n(p,s,o,h,d,c){return i(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="엔터프라이즈-네트워크-구성" tabindex="-1">엔터프라이즈 네트워크 구성 <a class="header-anchor" href="#엔터프라이즈-네트워크-구성" aria-label="Permalink to &quot;엔터프라이즈 네트워크 구성&quot;">​</a></h1><blockquote><p>프록시 서버, 사용자 정의 인증 기관(CA), 상호 전송 계층 보안(mTLS) 인증을 사용하는 엔터프라이즈 환경에서 Claude Code를 구성합니다.</p></blockquote><p>Claude Code는 환경 변수를 통해 다양한 엔터프라이즈 네트워크 및 보안 구성을 지원합니다. 여기에는 기업 프록시 서버를 통한 트래픽 라우팅, 사용자 정의 인증 기관(CA) 신뢰, 보안 강화를 위한 상호 전송 계층 보안(mTLS) 인증서 인증이 포함됩니다.</p><div class="info custom-block"><p class="custom-block-title">참고</p><p>이 페이지에 표시된 모든 환경 변수는 <a href="/claude-code-docs-ko/settings.html"><code>settings.json</code></a>에서도 구성할 수 있습니다.</p></div><h2 id="프록시-구성" tabindex="-1">프록시 구성 <a class="header-anchor" href="#프록시-구성" aria-label="Permalink to &quot;프록시 구성&quot;">​</a></h2><h3 id="환경-변수" tabindex="-1">환경 변수 <a class="header-anchor" href="#환경-변수" aria-label="Permalink to &quot;환경 변수&quot;">​</a></h3><p>Claude Code는 표준 프록시 환경 변수를 인식합니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># HTTPS 프록시 (권장)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> HTTPS_PROXY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">https://proxy.example.com:8080</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># HTTP 프록시 (HTTPS를 사용할 수 없는 경우)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> HTTP_PROXY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">http://proxy.example.com:8080</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 특정 요청에 대해 프록시 우회 - 공백 구분 형식</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> NO_PROXY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;localhost 192.168.1.1 example.com .example.com&quot;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 특정 요청에 대해 프록시 우회 - 쉼표 구분 형식</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> NO_PROXY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;localhost,192.168.1.1,example.com,.example.com&quot;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 모든 요청에 대해 프록시 우회</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> NO_PROXY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;*&quot;</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">참고</p><p>Claude Code는 SOCKS 프록시를 지원하지 않습니다.</p></div><h3 id="기본-인증" tabindex="-1">기본 인증 <a class="header-anchor" href="#기본-인증" aria-label="Permalink to &quot;기본 인증&quot;">​</a></h3><p>프록시에 기본 인증이 필요한 경우 프록시 URL에 자격 증명을 포함하세요:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> HTTPS_PROXY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">http://username:password@proxy.example.com:8080</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">주의</p><p>스크립트에 비밀번호를 하드코딩하지 마세요. 대신 환경 변수나 안전한 자격 증명 저장소를 사용하세요.</p></div><div class="tip custom-block"><p class="custom-block-title">팁</p><p>고급 인증(NTLM, Kerberos 등)이 필요한 프록시의 경우, 해당 인증 방법을 지원하는 LLM Gateway 서비스 사용을 고려하세요.</p></div><h2 id="ca-인증서-저장소" tabindex="-1">CA 인증서 저장소 <a class="header-anchor" href="#ca-인증서-저장소" aria-label="Permalink to &quot;CA 인증서 저장소&quot;">​</a></h2><p>기본적으로 Claude Code는 번들된 Mozilla CA 인증서와 운영 체제의 인증서 저장소를 모두 신뢰합니다. CrowdStrike Falcon 및 Zscaler와 같은 엔터프라이즈 TLS 검사 프록시는 루트 인증서가 OS 신뢰 저장소에 설치되어 있으면 추가 구성 없이 작동합니다.</p><div class="info custom-block"><p class="custom-block-title">참고</p><p>시스템 CA 저장소 통합에는 네이티브 Claude Code 바이너리 배포가 필요합니다. Node.js 런타임에서 실행할 때는 시스템 CA 저장소가 자동으로 병합되지 않습니다. 이 경우 엔터프라이즈 루트 CA를 신뢰하려면 <code>NODE_EXTRA_CA_CERTS=/path/to/ca-cert.pem</code>을 설정하세요.</p></div><p><code>CLAUDE_CODE_CERT_STORE</code>는 쉼표로 구분된 소스 목록을 허용합니다. 인식되는 값은 Claude Code와 함께 제공되는 Mozilla CA 세트를 위한 <code>bundled</code>와 운영 체제 신뢰 저장소를 위한 <code>system</code>입니다. 기본값은 <code>bundled,system</code>입니다.</p><p>번들된 Mozilla CA 세트만 신뢰하려면:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CLAUDE_CODE_CERT_STORE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">bundled</span></span></code></pre></div><p>OS 인증서 저장소만 신뢰하려면:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CLAUDE_CODE_CERT_STORE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">system</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">참고</p><p><code>CLAUDE_CODE_CERT_STORE</code>에는 전용 <code>settings.json</code> 스키마 키가 없습니다. <code>~/.claude/settings.json</code>의 <code>env</code> 블록이나 프로세스 환경에서 직접 설정하세요.</p></div><h2 id="사용자-정의-ca-인증서" tabindex="-1">사용자 정의 CA 인증서 <a class="header-anchor" href="#사용자-정의-ca-인증서" aria-label="Permalink to &quot;사용자 정의 CA 인증서&quot;">​</a></h2><p>엔터프라이즈 환경에서 사용자 정의 CA를 사용하는 경우, Claude Code가 직접 신뢰하도록 구성하세요:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> NODE_EXTRA_CA_CERTS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/path/to/ca-cert.pem</span></span></code></pre></div><h2 id="mtls-인증" tabindex="-1">mTLS 인증 <a class="header-anchor" href="#mtls-인증" aria-label="Permalink to &quot;mTLS 인증&quot;">​</a></h2><p>클라이언트 인증서 인증이 필요한 엔터프라이즈 환경:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 인증용 클라이언트 인증서</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CLAUDE_CODE_CLIENT_CERT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/path/to/client-cert.pem</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 클라이언트 개인 키</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CLAUDE_CODE_CLIENT_KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/path/to/client-key.pem</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 선택 사항: 암호화된 개인 키의 암호</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CLAUDE_CODE_CLIENT_KEY_PASSPHRASE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;your-passphrase&quot;</span></span></code></pre></div><h2 id="네트워크-접근-요구-사항" tabindex="-1">네트워크 접근 요구 사항 <a class="header-anchor" href="#네트워크-접근-요구-사항" aria-label="Permalink to &quot;네트워크 접근 요구 사항&quot;">​</a></h2><p>Claude Code는 다음 URL에 대한 접근이 필요합니다:</p><ul><li><code>api.anthropic.com</code>: Claude API 엔드포인트</li><li><code>claude.ai</code>: claude.ai 계정 인증</li><li><code>platform.claude.com</code>: Anthropic Console 계정 인증</li></ul><p>프록시 구성 및 방화벽 규칙에서 이러한 URL을 허용 목록에 추가하세요. 이는 컨테이너화된 환경이나 제한된 네트워크 환경에서 Claude Code를 사용할 때 특히 중요합니다.</p><p>네이티브 설치 프로그램 및 업데이트 확인에는 다음 URL도 필요합니다. 설치 프로그램과 자동 업데이터는 <code>storage.googleapis.com</code>에서 가져오고 플러그인 다운로드는 <code>downloads.claude.ai</code>를 사용하므로 두 가지 모두 허용 목록에 추가하세요. npm을 통해 Claude Code를 설치하거나 자체 바이너리 배포를 관리하는 경우, 최종 사용자에게는 접근이 필요하지 않을 수 있습니다:</p><ul><li><code>storage.googleapis.com</code>: Claude Code 바이너리 및 자동 업데이터용 다운로드 버킷</li><li><code>downloads.claude.ai</code>: 설치 스크립트, 버전 포인터, 매니페스트, 서명 키, 플러그인 실행 파일을 호스팅하는 CDN</li></ul><p><a href="/claude-code-docs-ko/chrome.html">Chrome 통합</a>은 WebSocket 브리지를 통해 브라우저 확장 프로그램에 연결합니다. Chrome에서 Claude를 사용하는 경우 아웃바운드 WebSocket 연결을 위해 <code>bridge.claudeusercontent.com</code>을 허용 목록에 추가하세요.</p><p><a href="/claude-code-docs-ko/claude-code-on-the-web.html">웹의 Claude Code</a> 및 <a href="/claude-code-docs-ko/code-review.html">코드 리뷰</a>는 Anthropic 관리 인프라에서 리포지토리에 연결합니다. GitHub Enterprise Cloud 조직에서 IP 주소로 접근을 제한하는 경우, <a href="https://docs.github.com/en/enterprise-cloud@latest/organizations/keeping-your-organization-secure/managing-security-settings-for-your-organization/managing-allowed-ip-addresses-for-your-organization#allowing-access-by-github-apps" target="_blank" rel="noreferrer">설치된 GitHub Apps에 대한 IP 허용 목록 상속</a>을 활성화하세요. Claude GitHub App은 IP 범위를 등록하므로 이 설정을 활성화하면 수동 구성 없이 접근이 허용됩니다. <a href="https://docs.github.com/en/enterprise-cloud@latest/organizations/keeping-your-organization-secure/managing-security-settings-for-your-organization/managing-allowed-ip-addresses-for-your-organization#adding-an-allowed-ip-address" target="_blank" rel="noreferrer">허용 목록에 범위를 수동으로 추가</a>하거나 다른 방화벽을 구성하려면 <a href="https://platform.claude.com/docs/en/api/ip-addresses" target="_blank" rel="noreferrer">Anthropic API IP 주소</a>를 참조하세요.</p><p>방화벽 뒤의 자체 호스팅 <a href="/claude-code-docs-ko/github-enterprise-server.html">GitHub Enterprise Server</a> 인스턴스의 경우, Anthropic 인프라가 GHES 호스트에 접근하여 리포지토리를 클론하고 리뷰 댓글을 게시할 수 있도록 동일한 <a href="https://platform.claude.com/docs/en/api/ip-addresses" target="_blank" rel="noreferrer">Anthropic API IP 주소</a>를 허용 목록에 추가하세요.</p><h2 id="추가-리소스" tabindex="-1">추가 리소스 <a class="header-anchor" href="#추가-리소스" aria-label="Permalink to &quot;추가 리소스&quot;">​</a></h2><ul><li><a href="/claude-code-docs-ko/settings.html">Claude Code 설정</a></li><li><a href="/claude-code-docs-ko/env-vars.html">환경 변수 참조</a></li><li><a href="/claude-code-docs-ko/troubleshooting.html">문제 해결 가이드</a></li></ul>`,40)])])}const u=a(l,[["render",n]]);export{k as __pageData,u as default};
